const a = [
  {"id":1856,"text":"Caplan syndrome consists of which of the following?","explanation":"Caplan syndrome is a specific clinical entity characterized by the presence of **rheumatoid arthritis (RA) in combination with pneumoconiosis**, particularly coal worker's pneumoconiosis or silicosis. It is important to note that Caplan syndrome is specifically associated with pneumoconiosis and not other forms of interstitial lung disease.\r\n\r\nThe syndrome was first described in coal miners with concomitant RA, but it can also occur in individuals exposed to other dust particles, such as silica. The pathogenesis of Caplan syndrome is not completely understood, but it is believed to involve the interaction between environmental exposures and an underlying genetic predisposition to developing RA.\r\n\r\nClinically, Caplan syndrome presents with characteristic nodular pulmonary opacities on chest radiographs, which are termed \"rheumatoid nodules.\" These nodules are typically found in the upper lobes of the lungs.","reference":"Nemakayala DR, Surmachevska N, Ramphul K. Caplan syndrome. In: StatPearls. StatPearls Publishing; 2022. Accessed May 16, 2022. http://www.ncbi.nlm.nih.gov/books/NBK499886/","responses":[{"text":"Silicosis and tuberculosis","correct":false,"visible":false},{"text":"Pneumoconiosis  and rheumatoid arthritis","correct":true,"visible":false},{"text":"Byssinosis and rheumatoid arthritis","correct":false,"visible":false},{"text":"Berriliosis","correct":false,"visible":false},{"text":"Asbestosis and tuberculosis","correct":false,"visible":false}]},{"id":7275,"text":"Which of the following is used to determine the pH of the buffer solution?","explanation":null,"reference":null,"responses":[{"text":"Weak acid","correct":false,"visible":false},{"text":"Acid and conjugate base","correct":true,"visible":false},{"text":"Weak and strong acid","correct":false,"visible":false},{"text":"Weak base","correct":false,"visible":false},{"text":"Strong acid","correct":false,"visible":false}]},{"id":7284,"text":"A doctor checking a chest X-ray notices a rib having the subclavian artery on it. Which of the following ribs has the groove for this artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 293.","responses":[{"text":"4","correct":false,"visible":false},{"text":"2","correct":false,"visible":false},{"text":"3","correct":false,"visible":false},{"text":"1","correct":true,"visible":false},{"text":"6","correct":false,"visible":false}]},{"id":7290,"text":"A 27-year-old man is brought to the emergency department after he suffered from a stab wound injury in the abdomen. The wound continues up to the central tendon of the diaphragm. Which of the following structures passing through the diaphragm can be the source of hemorrhage?","explanation":null,"reference":null,"responses":[{"text":"Inferior phrenic artery","correct":false,"visible":false},{"text":"Inferior vena cava","correct":true,"visible":false},{"text":"Aorta","correct":false,"visible":false},{"text":"Azygos vein","correct":false,"visible":false},{"text":"Hemiazygos vein","correct":false,"visible":false}]},{"id":7294,"text":"pH can be defined as the negative log of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Hydrogen ion concentration","correct":true,"visible":false},{"text":"Weak acid","correct":false,"visible":false},{"text":"Hydroxyl ion concentration","correct":false,"visible":false},{"text":"Weak base","correct":false,"visible":false},{"text":"Strong acid","correct":false,"visible":false}]},{"id":7305,"text":"Bucket handle movement of which ribs lead to the increase in transverse diameter during inspiration?","explanation":null,"reference":null,"responses":[{"text":"3-8","correct":false,"visible":false},{"text":"10-12","correct":false,"visible":false},{"text":"2-6","correct":false,"visible":false},{"text":"7-10","correct":true,"visible":false},{"text":"1-7","correct":false,"visible":false}]},{"id":7325,"text":"What will be the potassium value of the patient suffering from respiratory acidosis resulting from brain trauma?","explanation":null,"reference":null,"responses":[{"text":"2.5 mEq/L","correct":false,"visible":false},{"text":"3.5 mEq/L","correct":false,"visible":false},{"text":"6 mEq/L","correct":true,"visible":false},{"text":"4.5 mEq/L","correct":false,"visible":false},{"text":"4 mEq/L","correct":false,"visible":false}]},{"id":7337,"text":"Which of the following does not characterize the bronchopulmonary segment?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 335-336.","responses":[{"text":"Pyramidal in shape","correct":false,"visible":false},{"text":"Segmental bronchus","correct":false,"visible":false},{"text":"Has its own vein","correct":true,"visible":false},{"text":"Has its own artery","correct":false,"visible":false},{"text":"Independent functional unit","correct":false,"visible":false}]},{"id":7355,"text":"A 4-year-old boy presents to the emergency department with complaints of coughing and wheezing after swallowing 5 rupees coin. The pulmonologist used a bronchoscope to perform foreign body aspiration to remove the coin. What is the most expected place for trapping of the foreign body?","explanation":null,"reference":"Kumar S, Al-Abri R, Sharma A, Al-Kindi H, Mishra P. Management of pediatric tracheo bronchial foreign body aspiration. Oman Med J. 2010;25(4):e019. doi:10.5001/omj.2010.99","responses":[{"text":"Bronchioles","correct":false,"visible":false},{"text":"Lobule of lung","correct":false,"visible":false},{"text":"Left bronchus","correct":false,"visible":false},{"text":"Trachea","correct":false,"visible":false},{"text":"Right bronchus","correct":true,"visible":false}]},{"id":7362,"text":"A 40-year-old female with a known case of the human immunodeficiency virus (HIV) presents to the outpatient department with complaints of productive cough with sputum, fever with chills, and wheezing. Which of the following types of pneumonia is responsible for this?","explanation":null,"reference":null,"responses":[{"text":"Typical pneumonia","correct":true,"visible":false},{"text":"Aspiration pneumonia","correct":false,"visible":false},{"text":"Atypical pneumonia","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Bronchopulmonary pneumonia","correct":false,"visible":false}]},{"id":7393,"text":"In the 3rd week of development, notochord formation occurs that persists in adults as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Nucleus pulposus","correct":true,"visible":false},{"text":"Transverse process","correct":false,"visible":false},{"text":"Sternum","correct":false,"visible":false},{"text":"Vertebral arch","correct":false,"visible":false},{"text":"Vertebral body","correct":false,"visible":false}]},{"id":7405,"text":"What is the level of bifurcation of the trachea?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 333-334.","responses":[{"text":"Gastroesophageal junction","correct":false,"visible":false},{"text":"Sternal angle","correct":true,"visible":false},{"text":"T4","correct":false,"visible":false},{"text":"T3","correct":false,"visible":false},{"text":"T6","correct":false,"visible":false}]},{"id":7412,"text":"Which of the following enzymes degrade sphingomyelin?","explanation":null,"reference":null,"responses":[{"text":"Phosphatase","correct":false,"visible":false},{"text":"Ceramidase","correct":false,"visible":false},{"text":"Sphingomyelinase","correct":true,"visible":false},{"text":"Glucocerebrosidase","correct":false,"visible":false},{"text":"Glucosidase","correct":false,"visible":false}]},{"id":7469,"text":"A 70-year-old man presents to the outpatient department with a complaint of a bad cough and says, \"the chest appears suffocating to me and I am unable to breath due to chest tightness\". Which of the following is responsible for his symptoms?","explanation":null,"reference":null,"responses":[{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":true,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Compensatory respiratory alkalosis","correct":false,"visible":false}]},{"id":7475,"text":"Which of the following is not a part of the superior mediastinum?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 382.","responses":[{"text":"Arch of the aorta","correct":false,"visible":false},{"text":"Brachiocephalic vein","correct":false,"visible":false},{"text":"Superior vena cava","correct":false,"visible":false},{"text":"Subclavian artery","correct":false,"visible":false},{"text":"Heart","correct":true,"visible":false}]},{"id":7476,"text":"The body of the sternum joins with the manubrium of the sternum at the level of T4-T5, which corresponds to which of the following ribs?","explanation":null,"reference":null,"responses":[{"text":"4","correct":false,"visible":false},{"text":"2","correct":true,"visible":false},{"text":"6","correct":false,"visible":false},{"text":"3","correct":false,"visible":false},{"text":"1","correct":false,"visible":false}]},{"id":7483,"text":"Which of the following is the simplest hydrophilic moiety factor in phospholipids?","explanation":null,"reference":null,"responses":[{"text":"Hydroxyl","correct":true,"visible":false},{"text":"Sulfate","correct":false,"visible":false},{"text":"Phosphate","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Carbons","correct":false,"visible":false}]},{"id":7489,"text":"A 30-year-old patient presents to the emergency department with complaints of fever, chest pain, and blood-stained sputum. His blood culture shows lancet-shaped gram-positive diplococci. What is this organism?","explanation":null,"reference":null,"responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Haemophilus influenzae","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Klebsiella","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false}]},{"id":7490,"text":"Which type of cell in the respiratory system has cilia?","explanation":null,"reference":null,"responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Columnar cell","correct":true,"visible":false},{"text":"Goblet cell","correct":false,"visible":false},{"text":"Basal cell","correct":false,"visible":false},{"text":"Brush cell","correct":false,"visible":false}]},{"id":7491,"text":"A young man presents to the nearby clinic with complaints of shortness of breath and cough with a copious amount of mucus production. He is found infertile and is diagnosed with immotile cilia syndrome. What is defective in this syndrome?","explanation":null,"reference":null,"responses":[{"text":"Nexin link","correct":false,"visible":false},{"text":"Dynein arms","correct":true,"visible":false},{"text":"Central pair of microtubules","correct":false,"visible":false},{"text":"Axoneme","correct":false,"visible":false},{"text":"Peripheral microtubules","correct":false,"visible":false}]},{"id":7492,"text":"What is the type of epithelium found in the vocal cords of the larynx?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 353.","responses":[{"text":"Stratified squamous non-keratinized","correct":true,"visible":false},{"text":"Stratified cuboidal","correct":false,"visible":false},{"text":"Simple squamous","correct":false,"visible":false},{"text":"Columnar ciliated","correct":false,"visible":false},{"text":"Stratified squamous keratinized","correct":false,"visible":false}]},{"id":7499,"text":"Acute respiratory distress syndrome (ARDS) in adults is a deficiency of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Renin","correct":false,"visible":false},{"text":"CO2 tension","correct":false,"visible":false},{"text":"O2 tension","correct":true,"visible":false},{"text":"Angiotensin converting enzyme","correct":false,"visible":false},{"text":"Surfactant","correct":false,"visible":false}]},{"id":7509,"text":"Which of the following does not play any role in the embryological development of the upper respiratory tract?","explanation":null,"reference":null,"responses":[{"text":"Pharyngeal pouches","correct":false,"visible":false},{"text":"Pharyngeal clefts","correct":false,"visible":false},{"text":"Nasal placodes","correct":false,"visible":false},{"text":"Neural crest cells","correct":true,"visible":false},{"text":"Pharyngeal arches","correct":false,"visible":false}]},{"id":7511,"text":"Which one of the following is a term used to describe a lack of sufficient oxygen delivered to the tissues?","explanation":null,"reference":null,"responses":[{"text":"Anemia","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Anoxia","correct":false,"visible":false},{"text":"Hypoxia","correct":true,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":7512,"text":"Which of the following options correctly describes hypercapnia?","explanation":null,"reference":null,"responses":[{"text":"Buildup of carbon dioxide in body fluids","correct":true,"visible":false},{"text":"Excess carbon dioxide excretion","correct":false,"visible":false},{"text":"Decrease in negative ions of the plasma","correct":false,"visible":false},{"text":"Excess of oxygen in blood plasma","correct":false,"visible":false},{"text":"Buildup of bicarbonate ions in the blood plasma","correct":false,"visible":false}]},{"id":7514,"text":"After which of the following weeks does the large cavity from the thorax to the pelvis develop?","explanation":null,"reference":null,"responses":[{"text":"10th week","correct":false,"visible":false},{"text":"8th week","correct":false,"visible":false},{"text":"9th week","correct":false,"visible":false},{"text":"None of them","correct":true,"visible":false},{"text":"7th week","correct":false,"visible":false}]},{"id":7536,"text":"Which of these substances is used to synthesize prostaglandins?","explanation":null,"reference":null,"responses":[{"text":"Oxygen","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Nitric oxide","correct":false,"visible":false},{"text":"Arginine","correct":false,"visible":false},{"text":"Arachidonic acid","correct":true,"visible":false}]},{"id":7556,"text":"Alveoli are cup-shaped structures having very thin walls through which gaseous exchange between blood and air takes place. What lies in the region between two adjacent alveoli?","explanation":null,"reference":null,"responses":[{"text":"Alveolar phagocytes","correct":false,"visible":false},{"text":"Alveolar epithelium","correct":false,"visible":false},{"text":"Inter-alveolar septum","correct":true,"visible":false},{"text":"Alveolar ducts","correct":false,"visible":false},{"text":"Atrium","correct":false,"visible":false}]},{"id":7557,"text":"The bulk of carbon dioxide in the blood is carried in which of the following forms?","explanation":null,"reference":null,"responses":[{"text":"Carbaminohemoglobin","correct":false,"visible":false},{"text":"Dissolved in blood","correct":false,"visible":false},{"text":"Bicarbonate ion in red blood cells","correct":false,"visible":false},{"text":"Carbonic acid","correct":false,"visible":false},{"text":"Bicarbonate ion in plasma","correct":true,"visible":false}]},{"id":7558,"text":"Which of the following cells of the lungs secrete surfactant?","explanation":null,"reference":null,"responses":[{"text":"Secretory cells","correct":false,"visible":false},{"text":"Type 2 alveolar epithelial cells","correct":true,"visible":false},{"text":"Type 1 alveolar epithelial cells","correct":false,"visible":false},{"text":"Endothelial cells","correct":false,"visible":false},{"text":"Squamous epithelial cells of trachea","correct":false,"visible":false}]},{"id":7559,"text":"Strong signals from which of the following centers limit the tidal volume thereby increasing the respiratory rate?","explanation":null,"reference":null,"responses":[{"text":"Dorsal respiratory group of neurons","correct":false,"visible":false},{"text":"Apneustic centre","correct":false,"visible":false},{"text":"Pneumotaxic centre","correct":true,"visible":false},{"text":"Ventral respiratory group of neurons","correct":false,"visible":false},{"text":"Central chemoreceptors","correct":false,"visible":false}]},{"id":7565,"text":"Which of these represents the vital capacity?","explanation":null,"reference":null,"responses":[{"text":"Tidal volume + expiratory reserve volume","correct":false,"visible":false},{"text":"Tidal volume + inspiratory reserve volume + expiratory reserve volume","correct":true,"visible":false},{"text":"Tidal volume + inspiratory reserve volume","correct":false,"visible":false},{"text":"Tidal volume + expiratory reserve volume + residual volume","correct":false,"visible":false},{"text":"Residual volume + tidal volume + expiratory reserve volume","correct":false,"visible":false}]},{"id":7568,"text":"The increase in cardiac output during exercise is accompanied by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Sometimes decreased, sometimes increased pulmonary pressure","correct":false,"visible":false},{"text":"No increase in pulmonary pressure","correct":false,"visible":false},{"text":"Decrease in pulmonary pressure","correct":false,"visible":false},{"text":"Massive increase in pulmonary pressure","correct":false,"visible":false},{"text":"Slight increase in pulmonary pressure","correct":true,"visible":false}]},{"id":7579,"text":"What is the key difference between thromboxane A2 and prostaglandins?","explanation":null,"reference":null,"responses":[{"text":"Thromboxane A2 decreases platelet aggregation while prostaglandins increase it","correct":false,"visible":false},{"text":"Thromboxane A2 mediates pain while prostaglandins do not","correct":false,"visible":false},{"text":"Thromboxane A2 causes platelet aggregation while prostaglandins decrease it","correct":true,"visible":false},{"text":"Thromboxane A2 causes vasodilation while prostaglandins cause vasoconstriction","correct":false,"visible":false},{"text":"Thromboxane A2 mediates allergic reactions while prostaglandins do not","correct":false,"visible":false}]},{"id":7614,"text":"A 50-year-old female has experienced a 5 kg weightloss over the last 3 months. She recently developed low grade fever and cough with mucoid sputum production and after 2 weeks, she experienced blood streaked sputum. There are bilateral crackles in the left upper lobe on auscultation of the chest. The sputum smear shows bright red bacilli against a bluish background. Which of the following findings are most likely to be present in the sputum sample?","explanation":null,"reference":null,"responses":[{"text":"Foreign body giant cells","correct":false,"visible":false},{"text":"Gram-negative bacilli","correct":false,"visible":false},{"text":"Acid-fast bacilli","correct":true,"visible":false},{"text":"Branching septate hyphae","correct":false,"visible":false},{"text":"Charcot-Leyden crystals","correct":false,"visible":false}]},{"id":7615,"text":"A 12-year-old girl has a 7 year history of coughing, wheezing, and repeated attacks of difficulty in breathing. The attacks get more common during spring. During an episode of acute respiratory difficulty, physical examination shows that she is afebrile. Her lungs are hyper-resonant on percussion and chest radiograph shows increased lucency of all lung fields. Laboratory tests show an elevated serum IgE level and peripheral blood eosinophilia. Sputum sample is examined and it also has increased number of eosinophils. Which of the following histological features are most likely a characteristic feature of this condition?","explanation":null,"reference":null,"responses":[{"text":"Dilatation of bronchi and loss of elastic tissue","correct":false,"visible":false},{"text":"Patchy consolidation in lung parenchyma","correct":false,"visible":false},{"text":"Inflammatory destruction of bronchiolar walls","correct":false,"visible":false},{"text":"Alveolar and interstitial edema with sheets of macrophages","correct":false,"visible":false},{"text":"Remodeling of airways with smooth muscle hyperplasia","correct":true,"visible":false}]},{"id":7616,"text":"Which of the following types of cancer involves the chromosome 3p deletions and mutations in TP53, Rb?","explanation":null,"reference":null,"responses":[{"text":"Basal cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false}]},{"id":7617,"text":"Which of the following progresses from interstitial fibrosis, diffuse fibrosis to characteristic end-stage honeycomb appearance?","explanation":null,"reference":null,"responses":[{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Non specific interstitial pneumonia","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Cryptogenic organizing pneumonia","correct":false,"visible":false},{"text":"Usual interstitial pneumonia","correct":true,"visible":false}]},{"id":7618,"text":"Acid-fast staining or Ziehl–Neelsen staining is used to rule out the presence of Mycobacterium tuberculosis, which appears red in this stain. Which of the following property enables it to appear red under this particular type of stain?","explanation":null,"reference":null,"responses":[{"text":"Hydrophilic nature of its walls","correct":false,"visible":false},{"text":"Absorption of counter stain","correct":false,"visible":false},{"text":"Retention of dye due to the presence of mycolic acid","correct":true,"visible":false},{"text":"Discoloration by acid alcohol","correct":false,"visible":false},{"text":"Transmembrane channels in its walls","correct":false,"visible":false}]},{"id":7619,"text":"A 14-year-old girl from a village presented with anorexia, weight loss, and lethargy for the past 5 weeks. She also had several episodes of abdominal pain. History revealed that drinking unpasteurized milk was quite common in her region. Which of the following organisms would most likely be the causative agent in this condition?","explanation":null,"reference":null,"responses":[{"text":"Mycobacterium leprae","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false},{"text":"Mycobacterium ulcerans","correct":false,"visible":false},{"text":"Mycobacterium bovis","correct":true,"visible":false},{"text":"Mycobacterium avium","correct":false,"visible":false}]},{"id":7620,"text":"Which of the following terms is used to describe a bluish-purple discoloration of the mucosa and the skin due to reduced hemoglobin content in the body?","explanation":null,"reference":null,"responses":[{"text":"Anemia","correct":false,"visible":false},{"text":"Anorexia","correct":false,"visible":false},{"text":"Hypoxemia","correct":false,"visible":false},{"text":"Cyanosis","correct":true,"visible":false},{"text":"Hypoxia","correct":false,"visible":false}]},{"id":7621,"text":"Which of the following terms is used to indicate the benign neoplasm of glandular epithelial cells?","explanation":null,"reference":null,"responses":[{"text":"Papilloma","correct":false,"visible":false},{"text":"Choriocarcinoma","correct":false,"visible":false},{"text":"Sarcoma","correct":false,"visible":false},{"text":"Polyp","correct":false,"visible":false},{"text":"Adenoma","correct":true,"visible":false}]},{"id":7622,"text":"Which factor shifts the oxygen dissociation curve to the right?","explanation":null,"reference":null,"responses":[{"text":"Decrease in hydrogen ion concentration","correct":false,"visible":false},{"text":"Decrease in pH","correct":true,"visible":false},{"text":"Decrease in partial pressure of carbon dioxide","correct":false,"visible":false},{"text":"Decrease in concentration of 2,3 bis-phosphoglycerate","correct":false,"visible":false},{"text":"Decrease in temperature","correct":false,"visible":false}]},{"id":7626,"text":"A female patient was brought to the emergency department with chest pain. She was a known case of mediastinal lymphoma. Doppler's ultrasound revealed the presence of the milky fluid in the pleural cavity which points towards the obstruction of the thoracic duct by the tumor mass. Which of the following entities designates this condition?","explanation":null,"reference":null,"responses":[{"text":"Suppurative pleuritis","correct":false,"visible":false},{"text":"Miliary tuberculosis","correct":false,"visible":false},{"text":"Chylothorax","correct":true,"visible":false},{"text":"Pneumothorax","correct":false,"visible":false},{"text":"Filariasis","correct":false,"visible":false}]},{"id":7627,"text":"In which of the following conditions are cells unable to utilize oxygen?","explanation":null,"reference":null,"responses":[{"text":"Increase in pH","correct":false,"visible":false},{"text":"Carbon monoxide poisoning","correct":false,"visible":false},{"text":"Decreased 2,3 bis-phosphoglycerate","correct":false,"visible":false},{"text":"Cyanide poisoning","correct":true,"visible":false},{"text":"Decreased hydrogen ion concentration","correct":false,"visible":false}]},{"id":7628,"text":"Which of the following organisms is most likely to cause pneumonia in an immunocompromised patient?","explanation":null,"reference":null,"responses":[{"text":"Mycoplasma","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":true,"visible":false},{"text":"Haemophilus influenzae","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false}]},{"id":7630,"text":"Exposure to which of the following is most likely to cause mesothelioma?","explanation":null,"reference":null,"responses":[{"text":"Coal dust","correct":false,"visible":false},{"text":"Tobacco","correct":false,"visible":false},{"text":"Tin oxide","correct":false,"visible":false},{"text":"Silica","correct":false,"visible":false},{"text":"Asbestos","correct":true,"visible":false}]},{"id":7631,"text":"Which of the following carcinogens present in cigarettes accelerates heart rate and the activity of the nervous system?","explanation":null,"reference":null,"responses":[{"text":"Aromatic hydrocarbons","correct":false,"visible":false},{"text":"Nicotine","correct":true,"visible":false},{"text":"Asbestos","correct":false,"visible":false},{"text":"Silica","correct":false,"visible":false},{"text":"Nitric oxide","correct":false,"visible":false}]},{"id":7632,"text":"Which of the following is the most common cause of lung cancer?","explanation":null,"reference":null,"responses":[{"text":"Hydrocarbons","correct":false,"visible":false},{"text":"Tobacco","correct":true,"visible":false},{"text":"Radiation","correct":false,"visible":false},{"text":"Aromatic fumes","correct":false,"visible":false},{"text":"Sunlight","correct":false,"visible":false}]},{"id":7649,"text":"The peripheral chemoreceptors are stimulated maximally by which of the following chemical substance?","explanation":null,"reference":null,"responses":[{"text":"High concentration of hydrogen ions","correct":false,"visible":false},{"text":"High level of bicarbonate ions","correct":false,"visible":false},{"text":"Low partial pressure of oxygen","correct":true,"visible":false},{"text":"High pH in blood","correct":false,"visible":false},{"text":"High concentration of CO2","correct":false,"visible":false}]},{"id":7650,"text":"Which of the following is the equation which defines that the pKa of an acid is numerically equal to the pH of the solution when the molar concentration of the acid and its conjugate base are equal?","explanation":null,"reference":null,"responses":[{"text":"Haldane equation","correct":false,"visible":false},{"text":"Henderson-Hasselbalch equation","correct":true,"visible":false},{"text":"Hardy-Weinberg equation","correct":false,"visible":false},{"text":"Water dissociation constant","correct":false,"visible":false},{"text":"Michaelis-Menten equation","correct":false,"visible":false}]},{"id":7651,"text":"A 16-year-old male came to the emergency department with shortness of breath and drowsiness. He was in respiratory distress. On the chest x-ray, there was atelectasis of the lungs due to air accumulation. There was no history of trauma or perforating injury. This clinical picture is mostly seen in which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Traumatic pneumothorax","correct":false,"visible":false},{"text":"Spontaneous pneumothorax","correct":true,"visible":false},{"text":"Tension pneumothorax","correct":false,"visible":false},{"text":"Therapeutic pneumothorax","correct":false,"visible":false},{"text":"Hemopneumothorax","correct":false,"visible":false}]},{"id":7652,"text":"A 29-year-old female presented to the outpatient department with fever and cough. She was evaluated with a chest x-ray. Which of the following is the standard position for obtaining a routine adult chest radiograph?","explanation":null,"reference":null,"responses":[{"text":"Apical view","correct":false,"visible":false},{"text":"Lateral view","correct":false,"visible":false},{"text":"Anteroposterior (AP) view","correct":false,"visible":false},{"text":"Posteroanterior (PA) view","correct":true,"visible":false},{"text":"Lateral decubitus view","correct":false,"visible":false}]},{"id":7653,"text":"Asthma is characterized by reversible bronchoconstriction caused by airway hyperresponsiveness to a variety of stimuli. What is the fundamental abnormality in asthma?","explanation":null,"reference":null,"responses":[{"text":"Exaggerated Th-2 response to environmental allergens","correct":true,"visible":false},{"text":"Increased mucous secretion","correct":false,"visible":false},{"text":"Exaggerated Th-1 response to environmental allergens","correct":false,"visible":false},{"text":"Mast cell mobilization","correct":false,"visible":false},{"text":"Decreased airway responsiveness","correct":false,"visible":false}]},{"id":7654,"text":"On examination of histological slides of the lung, students got confused between different bronchioles. Which of the following is the identifying feature that distinguishes respiratory bronchioles from other bronchioles?","explanation":null,"reference":null,"responses":[{"text":"The diameter of lumen","correct":false,"visible":false},{"text":"The presence of glands","correct":false,"visible":false},{"text":"The type of epithelium","correct":false,"visible":false},{"text":"The interrupted wall of lumen","correct":true,"visible":false},{"text":"The number of cells","correct":false,"visible":false}]},{"id":7655,"text":"A 60-year-old male, known case of type-2 diabetes for the last 20 years, presents in the emergency room with anorexia, vomiting, and flank pain for the last year. On examination, he is lethargic, with blood pressure 90/60 mmHg, pulse 100/minute, respiratory rate 24/minute, his chest and abdomen are unremarkable. His creatinine is 8 mg%. His random blood sugar is 70 mg%. Arterial blood gases show a pH of 7.2, pCO2 of 30mmHg, and HCO3 of 16 mEq/L. Urine DR is normal. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Diabetic ketoacidosis","correct":false,"visible":false},{"text":"Uremic acidosis","correct":true,"visible":false},{"text":"Starvation ketoacidosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":false,"visible":false}]},{"id":7656,"text":"Which of the following types of hypoxia occurs when cells are destroyed by reactive oxygen species and can not utilize oxygen properly?","explanation":null,"reference":null,"responses":[{"text":"Anemic hypoxia","correct":false,"visible":false},{"text":"Histotoxic hypoxia","correct":true,"visible":false},{"text":"Stagnant hypoxia","correct":false,"visible":false},{"text":"Ischemic hypoxia","correct":false,"visible":false},{"text":"Anemic hypoxia","correct":false,"visible":false}]},{"id":7657,"text":"Which of the following enzymes catalyzes the formation of bicarbonate ions from water and carbon dioxide in the blood?","explanation":null,"reference":null,"responses":[{"text":"Alkaline phosphatase","correct":false,"visible":false},{"text":"Acetylcholinesterase","correct":false,"visible":false},{"text":"Adenylate cyclase","correct":false,"visible":false},{"text":"Carbonic anhydrase","correct":true,"visible":false},{"text":"Protein kinase","correct":false,"visible":false}]},{"id":7658,"text":"There is a person who has been consuming alcohol for a long time. His family wants him to get rid of this bad habit as it is injurious to health from a long-term perspective. He himself is well aware of the consequences but isn't able to just stop it all of a sudden. Which of the following terms is described as physical dependence of the body on some substance to function?","explanation":null,"reference":null,"responses":[{"text":"Incontinence","correct":false,"visible":false},{"text":"Habituation","correct":false,"visible":false},{"text":"Dysfunction","correct":false,"visible":false},{"text":"Addiction","correct":true,"visible":false},{"text":"Rehabilitation","correct":false,"visible":false}]},{"id":7661,"text":"A female patient came to the outpatient department with chest pain. Her X-ray reports showed the hard mass in her right chest . Upon bronchoscopy, it was confirmed to be lung cancer. Which of the following is the most common site for tracheobronchial cancers to occur?","explanation":null,"reference":null,"responses":[{"text":"Bronchopulmonary segment","correct":false,"visible":false},{"text":"Bronchi","correct":true,"visible":false},{"text":"Brochioles","correct":false,"visible":false},{"text":"Lung lobule","correct":false,"visible":false},{"text":"Alveoli","correct":false,"visible":false}]},{"id":7664,"text":"Which of the following statements is correct about the azygous vein?","explanation":null,"reference":null,"responses":[{"text":"Arises from left ascending lumbar vein","correct":false,"visible":false},{"text":"It drains into the inferior vena cava","correct":false,"visible":false},{"text":"It joins hemiazygos vein at T4 level","correct":false,"visible":false},{"text":"It ascends on the left side of the thorax","correct":false,"visible":false},{"text":"It passes from the aortic hiatus of the diaphragm","correct":true,"visible":false}]},{"id":7669,"text":"In the lung parenchyma of a deceased patient, a few darkly stained cells were seen. Upon careful observation, they appear to have dark granules in their cytoplasm. A few students pointed out that there are some phagocytosing cells in the alveolar walls which engulf dust and carbon particles and therefore appear to be darker. Which of the following cells are they most likely be talking about?","explanation":null,"reference":null,"responses":[{"text":"Type II pneumocytes","correct":false,"visible":false},{"text":"Epithelial cells","correct":false,"visible":false},{"text":"Type I pneumocytes","correct":false,"visible":false},{"text":"Squamous cells","correct":false,"visible":false},{"text":"Dust cells","correct":true,"visible":false}]},{"id":7672,"text":"Which of the following is not true about rhinitis?","explanation":null,"reference":null,"responses":[{"text":"Type-l hypersensitivity reaction","correct":false,"visible":false},{"text":"Histamine release","correct":false,"visible":false},{"text":"Eosinophilia","correct":false,"visible":false},{"text":"Vasoconstriction","correct":true,"visible":false},{"text":"Nasal congestion","correct":false,"visible":false}]},{"id":7678,"text":"A person is nervous and is breathing rapidly. It can lead to which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Both respiratory acidosis and alkalosis","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":true,"visible":false}]},{"id":7679,"text":"What is a chronic inflammatory condition of the lung airways resulting in episodic airflow obstruction called?","explanation":null,"reference":null,"responses":[{"text":"Pneumonia","correct":false,"visible":false},{"text":"Allergic rhinitis","correct":false,"visible":false},{"text":"Angioedema","correct":false,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false},{"text":"Asthma","correct":true,"visible":false}]},{"id":7681,"text":"Which of the following shifts the oxygen hemoglobin dissociation curve to the left?","explanation":null,"reference":null,"responses":[{"text":"Fever","correct":false,"visible":false},{"text":"Increase in CO2","correct":false,"visible":false},{"text":"Increase in 2,3-biphosphoglycerate","correct":false,"visible":false},{"text":"Acidosis","correct":false,"visible":false},{"text":"Fetal hemoglobin","correct":true,"visible":false}]},{"id":7683,"text":"A 40-year-old female presents in the emergency room with severe cough, fever, and chest pain. Her COVID-19 PCR is positive. On examination, she is lethargic, with blood pressure 100/60mmHg, pulse 120/minute, respiratory rate 30/minute. Her chest is full of crepts. Arterial blood gases show pH of 7.1,  pCO2 of 60mmHg, and HCO3 of 30 mEq/L. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Mixed metabolic and respiratory acidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":true,"visible":false},{"text":"Uremic ketoacidosis","correct":false,"visible":false}]},{"id":7685,"text":"During severe exercise, the volume of air inspired and expired may increase to as great as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Vital capacity","correct":true,"visible":false},{"text":"Functional residual capacity","correct":false,"visible":false},{"text":"Inspiratory reserve volume","correct":false,"visible":false},{"text":"Expiratory reserve volume","correct":false,"visible":false},{"text":"Residual volume","correct":false,"visible":false}]},{"id":7687,"text":"The pulmonary alveoli are cup-shaped structures and are composed of many cells. Which of the following are the alveolar cells present in alveoli that are cuboidal in shape?","explanation":null,"reference":null,"responses":[{"text":"Great alveolar cells","correct":true,"visible":false},{"text":"Alveolar atria","correct":false,"visible":false},{"text":"Alveolar sac","correct":false,"visible":false},{"text":"Type 1 alveolar cells","correct":false,"visible":false},{"text":"Squamous alveolar cells","correct":false,"visible":false}]},{"id":7688,"text":"In the normal systemic arterial blood, the total quantity of oxygen is bound with hemoglobin and it is 96% saturated. Upon passing through the tissue capillaries, this amount is reduced and the hemoglobin is now 75% saturated with oxygen. What will be the partial pressure of oxygen (P02) in this blood in which hemoglobin is 75% saturated?","explanation":null,"reference":null,"responses":[{"text":"60 mmHg","correct":false,"visible":false},{"text":"80 mmHg","correct":false,"visible":false},{"text":"100 mmHg","correct":false,"visible":false},{"text":"20 mmHg","correct":false,"visible":false},{"text":"40 mmHg","correct":true,"visible":false}]},{"id":7689,"text":"Which of the following muscles are involved in inspiration during pulmonary ventilation?","explanation":null,"reference":null,"responses":[{"text":"Diaphragm and external intercostal muscles","correct":true,"visible":false},{"text":"Diaphragm and internal intercostal muscles","correct":false,"visible":false},{"text":"Internal and external intercostal muscles","correct":false,"visible":false},{"text":"Rectus abdominis and internal intercostal muscles","correct":false,"visible":false},{"text":"Scalene muscles and internal intercostal muscles","correct":false,"visible":false}]},{"id":7690,"text":"Paradoxical breathing due to injury of the anterolateral chest wall is known as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Pigeon chest","correct":false,"visible":false},{"text":"Flail chest","correct":true,"visible":false},{"text":"Scoliosis","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Kyphosis","correct":false,"visible":false}]},{"id":7691,"text":"The cartilaginous, muscular, and connective tissue components of the trachea and lungs are derived from which of the following surrounding structures of the foregut?","explanation":null,"reference":null,"responses":[{"text":"Endoderm","correct":false,"visible":false},{"text":"Splanchnic mesoderm","correct":true,"visible":false},{"text":"Neural crest cells","correct":false,"visible":false},{"text":"Ectoderm","correct":false,"visible":false},{"text":"Somatic mesoderm","correct":false,"visible":false}]},{"id":7692,"text":"An infant born at the 24th week of gestation develops worsening respiratory distress. Her chest x-ray showed honeycomb appearance of the lungs. What will be the diagnosis of the infant?","explanation":null,"reference":null,"responses":[{"text":"Agenesis of lung","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Pulmonary hypoplasia","correct":false,"visible":false},{"text":"Accessory lung","correct":false,"visible":false},{"text":"Congenital lung cysts","correct":true,"visible":false}]},{"id":7694,"text":"During the discussion of the histology of sense organs, students were asked to identify the olfactory epithelium. Which of the following is correct about olfactory epithelium?","explanation":null,"reference":null,"responses":[{"text":"Simple cuboidal","correct":false,"visible":false},{"text":"Pseudo-stratified columnar without goblet cells","correct":true,"visible":false},{"text":"Simple columnar ciliated","correct":false,"visible":false},{"text":"Pseudo-stratified columnar with goblet cells","correct":false,"visible":false},{"text":"Tall columnar with microvilli","correct":false,"visible":false}]},{"id":7696,"text":"A 60-year-old man has had fever, night sweats, and a 7 kg weight loss over the past 4 months. In the past month, he has had episodes of hemoptysis. He dies of respiratory failure and hypoxemia. Infection with which of the following organisms is most likely to have produced these findings?","explanation":null,"reference":null,"responses":[{"text":"Candida albicans","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Influenza","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":true,"visible":false}]},{"id":7697,"text":"The capacity for a normal understanding of what people are feeling appears to be central to the human practice of medicine. This ability is best described as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Empathy","correct":true,"visible":false},{"text":"Emotional dissonance","correct":false,"visible":false},{"text":"Genetic characteristics","correct":false,"visible":false},{"text":"Personality types","correct":false,"visible":false},{"text":"Good auditory capacity","correct":false,"visible":false}]},{"id":7699,"text":"Respiratory acidosis occurs as a result of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Lung disease: causing increased retention of CO2","correct":true,"visible":false},{"text":"Kidney disease, causing increased retention of bicarbonate","correct":false,"visible":false},{"text":"Lung disease: causing increased exhalation of CO2","correct":false,"visible":false},{"text":"Kidney disease: causing increased excretion of bicarbonate","correct":false,"visible":false},{"text":"Increased bicarbonate infusion","correct":false,"visible":false}]},{"id":7700,"text":"A 70-year-old male came to the outpatient department with shortness of breath and productive cough of yellow sputum. He also had a clinical history of high-grade fever for 5 days. On the chest x-ray, there was fluid inside the pleural cavity. Which of the following is the most probable etiology of fluid in this patient?","explanation":null,"reference":null,"responses":[{"text":"Pneumonia","correct":true,"visible":false},{"text":"Cardiomyopathy","correct":false,"visible":false},{"text":"Congestive heart failure","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false}]},{"id":7704,"text":"The decrease in oxygen affinity of hemoglobin when blood pH falls is called which of the following?","explanation":null,"reference":null,"responses":[{"text":"Haldane's effect","correct":false,"visible":false},{"text":"Bohr's effect","correct":true,"visible":false},{"text":"Hawthorn effect","correct":false,"visible":false},{"text":"Henry's effect","correct":false,"visible":false},{"text":"Hamburger effect","correct":false,"visible":false}]},{"id":7707,"text":"Which of the following is a measure of the overall disease burden expressed as a number of years lost due to ill health, disability, or early death adopted by the World Health Organization (WHO) in 2000?","explanation":null,"reference":null,"responses":[{"text":"YLL (Years of Lost Life)","correct":false,"visible":false},{"text":"Morbidity","correct":false,"visible":false},{"text":"Disability-adjusted life years (DALYs)","correct":true,"visible":false},{"text":"YLD (Years Lost to Disability)","correct":false,"visible":false},{"text":"Surveillance","correct":false,"visible":false}]},{"id":7710,"text":"The ability of the lungs to return to their normal size after stretching is known as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Compliance","correct":false,"visible":false},{"text":"Capacitance","correct":false,"visible":false},{"text":"Resistance","correct":false,"visible":false},{"text":"Resilience","correct":false,"visible":false},{"text":"Elasticity","correct":true,"visible":false}]},{"id":7712,"text":"The trachea is part of the conducting portion of the respiratory system. It is composed of the mucosa lined by pseudostratified ciliated columnar epithelium, glands in submucosa, cartilage and adventitia. Which of the following structures has the same histological appearance as the trachea?","explanation":null,"reference":null,"responses":[{"text":"Respiratory bronchioles","correct":false,"visible":false},{"text":"Extra-pulmonary bronchi","correct":true,"visible":false},{"text":"Intra-pulmonary bronchi","correct":false,"visible":false},{"text":"Pre-terminal bronchioles","correct":false,"visible":false},{"text":"Terminal bronchioles","correct":false,"visible":false}]},{"id":7715,"text":"A 50-year-old pregnant female presents in the emergency room with vomiting and upper abdominal pain for the last 2 days. On examination, she is lethargic, with blood pressure 90/60 mmHg, pulse 120/minute, respiratory rate 30/minute, and 101°F temperature. Her chest is clear while her abdomen is mildly tender in the epigastrium. Her random blood sugar is 400mg% and arterial blood gases show a pH of 7.1, pCO2 of 2OmmHg, and HCO3 of 10 mEq/L. Urine shows 3+ ketones. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Fasting ketoacidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":false,"visible":false}]},{"id":7716,"text":"No single test can secure a diagnosis of asthma. Which of the following is the most helpful and preferred method for establishing the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Arterial blood gases","correct":false,"visible":false},{"text":"Pulse oximeter","correct":false,"visible":false},{"text":"Chest x-ray","correct":false,"visible":false},{"text":"Spirometry","correct":true,"visible":false},{"text":"C.T scan of chest","correct":false,"visible":false}]},{"id":7718,"text":"Which of the following protein concentrations indicates that the fluid collected in the pleural cavity is an exudative fluid when serum protein content is normal?","explanation":null,"reference":null,"responses":[{"text":"50 g/L","correct":true,"visible":false},{"text":"30 g/L","correct":false,"visible":false},{"text":"10 g/L","correct":false,"visible":false},{"text":"5 g/L","correct":false,"visible":false},{"text":"3 g/L","correct":false,"visible":false}]},{"id":7720,"text":"Each molecule of hemoglobin can transport how much oxygen?","explanation":null,"reference":null,"responses":[{"text":"16 atoms of oxygen","correct":false,"visible":false},{"text":"4 atoms of oxygen","correct":false,"visible":false},{"text":"2 molecules of oxygen","correct":false,"visible":false},{"text":"4 molecules of oxygen","correct":true,"visible":false},{"text":"8 molecules of oxygen","correct":false,"visible":false}]},{"id":7721,"text":"Gases such as oxygen and carbon dioxide cross the plasma membrane by which of the following methods?","explanation":null,"reference":null,"responses":[{"text":"Secondary active transport","correct":false,"visible":false},{"text":"Passive diffusion through the lipid bilayer","correct":true,"visible":false},{"text":"Specific gas transport proteins","correct":false,"visible":false},{"text":"Facilitated diffusion","correct":false,"visible":false},{"text":"Primary active transport","correct":false,"visible":false}]},{"id":7722,"text":"A 32-year-old man after a road traffic accident is having trouble breathing. Upon reaching the emergency department his lung function test was done and his functional residual capacity was found to be reduced. This capacity indicates which of the following?","explanation":null,"reference":null,"responses":[{"text":"The amount of air remaining in the lungs after maximum expiration","correct":false,"visible":false},{"text":"The amount of air inspired and expired during each normal breath","correct":false,"visible":false},{"text":"Combination of inspiratory reserve volume and tidal volume","correct":false,"visible":false},{"text":"Amount of air expelled out after each normal expiration","correct":false,"visible":false},{"text":"The amount of air remaining in the lungs after normal expiration","correct":true,"visible":false}]},{"id":7724,"text":"A 55-year-old male was admitted to the hospital with complaints of shortness of breath for a day, he had a history of hip replacement surgery and he was immobile. He was a suspected case of pulmonary embolism. Which is the gold standard investigation for the diagnosis of pulmonary embolism?","explanation":null,"reference":null,"responses":[{"text":"V/Q scan","correct":false,"visible":false},{"text":"Echocardiography","correct":false,"visible":false},{"text":"Pulmonary angiography","correct":true,"visible":false},{"text":"Chest x-ray","correct":false,"visible":false},{"text":"Electrocardiography","correct":false,"visible":false}]},{"id":7725,"text":"A patient came to the emergency department. His pulse and blood pressure were undetectable. While his history was being taken, the doctor came to know that the patient had severe hypertension. An immediate X-ray was ordered and it showed fluid in the pleural cavity following an aortic aneurysm and pleuritis. What condition would the patient most likely be suffering from?","explanation":null,"reference":null,"responses":[{"text":"Hemothorax","correct":true,"visible":false},{"text":"Hydrothorax","correct":false,"visible":false},{"text":"Chylothorax","correct":false,"visible":false},{"text":"Tension pneumothorax","correct":false,"visible":false},{"text":"Hydropneumothorax","correct":false,"visible":false}]},{"id":7726,"text":"During an exam, the teacher asked the student that in which period of lung maturation, the cuboidal respiratory bronchioles change into thin, flat cells, the blood-air barrier is established and respiration becomes possible. What should be the answer of the student?","explanation":null,"reference":null,"responses":[{"text":"Late fetal period to one year","correct":false,"visible":false},{"text":"2 years to 8 years","correct":false,"visible":false},{"text":"5 to 17 weeks","correct":false,"visible":false},{"text":"24 weeks to late fetal period","correct":true,"visible":false},{"text":"16 to 25 weeks","correct":false,"visible":false}]},{"id":7727,"text":"The respiratory part of the respiratory system is responsible for the diffusion of gases at the level of alveoli. Which type of cell is responsible for exchanging gases?","explanation":null,"reference":null,"responses":[{"text":"Type 1 pneumocytes","correct":true,"visible":false},{"text":"Dust cells","correct":false,"visible":false},{"text":"Clara cells","correct":false,"visible":false},{"text":"Macrophages","correct":false,"visible":false},{"text":"Type 2 pneumocytes","correct":false,"visible":false}]},{"id":7729,"text":"Which of the following features clearly distinguishes bronchioles from bronchi under the light microscope?","explanation":null,"reference":null,"responses":[{"text":"The absence of glands","correct":true,"visible":false},{"text":"The type of glands","correct":false,"visible":false},{"text":"The type of epithelium","correct":false,"visible":false},{"text":"The presence of cartilage","correct":false,"visible":false},{"text":"The presence of smooth muscle","correct":false,"visible":false},{"text":"The type of cartilage","correct":false,"visible":false}]},{"id":7731,"text":"A one-week-old infant was brought by his mother complaining of frequent drooling of saliva and immediate regurgitation of milk when fed. Which of the following could be the diagnosis of the child?","explanation":null,"reference":null,"responses":[{"text":"Tracheal bronchus","correct":false,"visible":false},{"text":"Laryngo-tracheoesophageal cleft","correct":false,"visible":false},{"text":"Congenital lung cysts","correct":false,"visible":false},{"text":"Tracheo-esophageal fistula","correct":true,"visible":false},{"text":"Tracheal stenosis","correct":false,"visible":false}]},{"id":7732,"text":"A 42-year-old male patient comes to the emergency with complaints of fever with chills and cough for one week with a large amount of sputum and pain in the chest. Community-acquired pneumonia is suspected. What is the most common cause in such a case?","explanation":null,"reference":null,"responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Moraxella catarrhalis","correct":false,"visible":false}]},{"id":7733,"text":"What is the most common route carbon dioxide takes to be transported to the cells?","explanation":"The majority of carbon dioxide (CO₂) produced in the body's cells is transported to the lungs for elimination primarily **in the form of bicarbonate ions**.\r\n\r\nAfter being produced as a metabolic byproduct in cells, CO₂ diffuses into red blood cells. Inside the red blood cell, carbon dioxide reacts with water, catalyzed by the enzyme carbonic anhydrase, forming carbonic acid (H₂CO₃). This carbonic acid quickly dissociates into bicarbonate (HCO₃⁻) ions and hydrogen (H⁺) ions. The bicarbonate ions move out of the red blood cell and into the plasma in exchange for chloride ions – a process termed the \"chloride shift.\" In the lungs, the reaction reverses, liberating CO₂ to be exhaled. Approximately 70% of CO₂ is transported this way, making the bicarbonate ion method the most common route of CO₂ transport.","reference":"Hall, John E., and Michael E Hall. Guyton and Hall Textbook of Medical Physiology. 14th ed. Philadelphia, PA: Elsevier, 2020: 528.","responses":[{"text":"By dissolving in plasma","correct":false,"visible":false},{"text":"In the form of bicarbonate ions","correct":true,"visible":false},{"text":"In the form of carboxy hemoglobin","correct":false,"visible":false},{"text":"By binding to plasma proteins","correct":false,"visible":false},{"text":"In the form of carbaminohemoglobin","correct":false,"visible":false}]},{"id":7734,"text":"The rate of diffusion of a substance is inversely proportional to which of the following?","explanation":null,"reference":null,"responses":[{"text":"Square root of  the molecular weight","correct":true,"visible":false},{"text":"Solubility","correct":false,"visible":false},{"text":"Cross-sectional area of the fluid","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Partial pressure difference between the fluids","correct":false,"visible":false}]},{"id":7735,"text":"The lymphatic drainage of lung roots is via which of the following?","explanation":null,"reference":null,"responses":[{"text":"Subpleural plexus","correct":false,"visible":false},{"text":"Superficial lymphatic plexus","correct":false,"visible":false},{"text":"Parasternal lymph nodes","correct":false,"visible":false},{"text":"Thoracic duct","correct":false,"visible":false},{"text":"Deep lymphatic plexus","correct":true,"visible":false}]},{"id":7736,"text":"Which of the following is a feature that is present only in the thoracic vertebra?","explanation":null,"reference":null,"responses":[{"text":"Inferior articular facet","correct":false,"visible":false},{"text":"Costal facet","correct":true,"visible":false},{"text":"Intervertebral foramen","correct":false,"visible":false},{"text":"Superior articular facet","correct":false,"visible":false},{"text":"Laminae","correct":false,"visible":false}]},{"id":7737,"text":"A 32-year-old lady presents with a 2-day history of shortness of breath, fever, and cough. On examination, she is tachypneic, dyspneic, and shows low blood oxygen saturation. There are no signs of cardiac failure. Chest x-ray shows bilateral lung infiltrates. Which of the following best describes the lung morphology on microscopy?","explanation":null,"reference":null,"responses":[{"text":"Eosinophils and mast cells in abundance","correct":false,"visible":false},{"text":"Large, dilated alveoli with bullae formation","correct":false,"visible":false},{"text":"Asbestos bodies in macrophages","correct":false,"visible":false},{"text":"Collapsed alveoli with hyaline membranes","correct":true,"visible":false},{"text":"Epithelioid granulomas with caseous necrosis","correct":false,"visible":false}]},{"id":7738,"text":"The hemoglobin bound to oxygen in the normal systemic arterial blood is 98% saturated. Upon passing through the tissue capillaries, this is reduced to 75% saturation. How much oxygen is transported from the lungs to the tissues by every 100 ml of blood flow?","explanation":null,"reference":null,"responses":[{"text":"20 ml","correct":false,"visible":false},{"text":"10 ml","correct":false,"visible":false},{"text":"15 ml","correct":false,"visible":false},{"text":"40 ml","correct":false,"visible":false},{"text":"05 ml","correct":true,"visible":false}]},{"id":7739,"text":"Which of the following compounds is the most effective at maintaining the physiological pH?","explanation":null,"reference":null,"responses":[{"text":"Bicarbonate buffer","correct":true,"visible":false},{"text":"Phosphate buffer","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Sodium","correct":false,"visible":false}]},{"id":7742,"text":"The partial pressure of oxygen in the venous blood of a 20-year-old athlete is found to be 40 mmHg. What will be his hemoglobin saturation in this blood sample?","explanation":null,"reference":null,"responses":[{"text":"25%","correct":false,"visible":false},{"text":"50%","correct":false,"visible":false},{"text":"40%","correct":false,"visible":false},{"text":"97%","correct":false,"visible":false},{"text":"75%","correct":true,"visible":false}]},{"id":7743,"text":"In a section of lung tissue consisting predominantly of alveoli, a tubule about 2 mm in diameter is observed that contains smooth muscle and cartilage in its wall. Which of the following is the tubule discussed above?","explanation":null,"reference":null,"responses":[{"text":"Trachea","correct":false,"visible":false},{"text":"Bronchus","correct":true,"visible":false},{"text":"Alveolar sac","correct":false,"visible":false},{"text":"Bronchiole","correct":false,"visible":false},{"text":"Alveolar duct","correct":false,"visible":false}]},{"id":7744,"text":"A 25-year-old male was admitted to the ward with complaints of shortness of breath for a day. He had a history of long hours travel. There is a positive family history of thrombosis in his first-degree relative. On investigation, a chest x-ray shows Westermark's sign and Hampton's hump signs. Which is the most probable diagnosis of these findings?","explanation":null,"reference":null,"responses":[{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":true,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Atelectasis","correct":false,"visible":false},{"text":"Asbestosis","correct":false,"visible":false}]},{"id":7745,"text":"The triradiate ligament of the head of the rib connects which of the following?","explanation":null,"reference":null,"responses":[{"text":"Neck of rib to transverse process of vertebra","correct":false,"visible":false},{"text":"Neck of rib to spinous process","correct":false,"visible":false},{"text":"Head of rib to two adjacent vertebrae","correct":true,"visible":false},{"text":"Tubercle of rib to tip of transverse process","correct":false,"visible":false},{"text":"Crest of rib to superior transverse process","correct":false,"visible":false}]},{"id":7746,"text":"What is the pH of water?","explanation":null,"reference":null,"responses":[{"text":"5","correct":false,"visible":false},{"text":"9","correct":false,"visible":false},{"text":"11","correct":false,"visible":false},{"text":"7","correct":true,"visible":false},{"text":"3","correct":false,"visible":false}]},{"id":7747,"text":"As one ascends to higher than 3000 meters above sea level, what will be the changes in alveolar P02 and PCO2?","explanation":null,"reference":null,"responses":[{"text":"Decrease in P02, decrease In PCO2","correct":true,"visible":false},{"text":"Increase in both P02 and PCO2","correct":false,"visible":false},{"text":"Decrease in P02, increase In PCO2","correct":false,"visible":false},{"text":"Increase in P02, decrease In PCO2","correct":false,"visible":false},{"text":"No change","correct":false,"visible":false}]},{"id":7748,"text":"On examination of tracheal slides, students observe mixed types of glands in the submucosa. Which of the following types of glands are these?","explanation":null,"reference":null,"responses":[{"text":"Simple tubulo-alveolar glands","correct":false,"visible":false},{"text":"Branched tubulo-alveolar glands","correct":true,"visible":false},{"text":"Branched alveolar glands","correct":false,"visible":false},{"text":"Branched tubular glands","correct":false,"visible":false},{"text":"Simple tubular glands","correct":false,"visible":false}]},{"id":7749,"text":"A 25-year-old man has a routine chest x-ray as a part of the visa process. His chest x-ray reveals a rounded, very high-density structure over the right lung. The given explanation best corresponds to which of the following structures?","explanation":null,"reference":null,"responses":[{"text":"Fat","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false},{"text":"Fluid","correct":false,"visible":false},{"text":"Metal","correct":true,"visible":false},{"text":"Gas","correct":false,"visible":false}]},{"id":7752,"text":"A 40-year-old man presents with high-grade fever (102°F), productive cough, and chest pain. On auscultation, breath sounds on the lower right chest are very loud, high pitched with a gap in between inspiration and expiration, and expiration is longer than inspiration. Which of the following is most likely to be the type of breath sounds?","explanation":null,"reference":null,"responses":[{"text":"Vesicular breath sounds","correct":false,"visible":false},{"text":"Bronchial vesicular breath sounds","correct":false,"visible":false},{"text":"Bronchial breath sounds","correct":true,"visible":false},{"text":"Added breath sounds","correct":false,"visible":false},{"text":"Tracheal breath sounds","correct":false,"visible":false}]},{"id":7755,"text":"An interalveolar septum consists of two layers of squamous epithelial cells with blood capillary and specialized cells called which of the following?","explanation":null,"reference":null,"responses":[{"text":"Basal cells","correct":false,"visible":false},{"text":"Receptor cells","correct":false,"visible":false},{"text":"Dust cells","correct":true,"visible":false},{"text":"Sustentacular cells","correct":false,"visible":false},{"text":"Conical cells","correct":false,"visible":false}]},{"id":7757,"text":"A 32-year-old male underwent a chest x-ray due to a job process. His chest x-ray was unremarkable. How the rotation of chest x-ray can be assessed?","explanation":null,"reference":null,"responses":[{"text":"By counting the ribs","correct":false,"visible":false},{"text":"By identifying spine behind the heart","correct":false,"visible":false},{"text":"By looking at the orientation of ribs","correct":false,"visible":false},{"text":"By looking at the sternal ends of the clavicles","correct":true,"visible":false},{"text":"By looking at the lucency of lungs","correct":false,"visible":false}]},{"id":7758,"text":"Pacemaker cells for setting the respiratory rate are present in which of the following area?","explanation":null,"reference":null,"responses":[{"text":"Pre-Botzinger complex","correct":true,"visible":false},{"text":"Pneumotaxic center","correct":false,"visible":false},{"text":"Dorsal respiratory group of neurons","correct":false,"visible":false},{"text":"Apneustic center","correct":false,"visible":false},{"text":"Cerebral cortex","correct":false,"visible":false}]},{"id":7763,"text":"Which of the following is correct about the superior thoracic inlet of the thorax?","explanation":null,"reference":null,"responses":[{"text":"An asymmetrical shape","correct":false,"visible":false},{"text":"An oblong shape","correct":false,"visible":false},{"text":"An anteroposterior diameter greater than transverse diameter","correct":false,"visible":false},{"text":"A transverse diameter equal to the anteroposterior diameter","correct":false,"visible":false},{"text":"A transverse diameter greater than anteroposterior diameter","correct":true,"visible":false}]},{"id":7766,"text":"Pulmonary arteries emerge from the pulmonary trunk at which level?","explanation":null,"reference":null,"responses":[{"text":"Fourth intercostal space","correct":false,"visible":false},{"text":"First costal cartilage","correct":false,"visible":false},{"text":"Third costal cartilage","correct":false,"visible":false},{"text":"Second costal cartilage","correct":false,"visible":false},{"text":"Sternal angle","correct":true,"visible":false}]},{"id":7767,"text":"Community-acquired pneumonia is mostly caused by specific bacteria. The most common organism can be diagnosed in the lab by which of the following test?","explanation":null,"reference":null,"responses":[{"text":"On the Gram's staining","correct":true,"visible":false},{"text":"Growth on the chocolate agar","correct":false,"visible":false},{"text":"Type of hemolysis","correct":false,"visible":false},{"text":"Bacitracin sensitivity","correct":false,"visible":false},{"text":"Optochin sensitivity","correct":false,"visible":false}]},{"id":7768,"text":"Which of the following is a characteristic feature of the thoracic vertebra?","explanation":null,"reference":null,"responses":[{"text":"Foramen transversarium","correct":false,"visible":false},{"text":"Bifid spinous process","correct":false,"visible":false},{"text":"Facet for the dens","correct":false,"visible":false},{"text":"Heart shaped body","correct":true,"visible":false},{"text":"Dens","correct":false,"visible":false}]},{"id":7769,"text":"A patient comes into the emergency department with a rib fracture. His breathing is painful, so he is taking rapid, small breaths. His respiratory rate is 40/min and his tidal volume is 200 ml. What would be his minute respiratory volume?","explanation":null,"reference":null,"responses":[{"text":"4600 ml/min","correct":false,"visible":false},{"text":"200 ml/min","correct":false,"visible":false},{"text":"400 ml/min","correct":false,"visible":false},{"text":"8000 ml/min","correct":true,"visible":false},{"text":"2000 ml/min","correct":false,"visible":false}]},{"id":7770,"text":"The first two posterior intercostal arteries arise from which of the following?","explanation":null,"reference":null,"responses":[{"text":"Arch of aorta","correct":false,"visible":false},{"text":"Pulmonary trunk","correct":false,"visible":false},{"text":"Costocervical trunk","correct":true,"visible":false},{"text":"Ascending aorta","correct":false,"visible":false},{"text":"Brachiocephalic trunk","correct":false,"visible":false}]},{"id":7771,"text":"In prolapse of the intervertebral disc, pressure is exerted on which of the following?","explanation":null,"reference":null,"responses":[{"text":"Azygous vein","correct":false,"visible":false},{"text":"Spinal nerve","correct":true,"visible":false},{"text":"Vertebral artery","correct":false,"visible":false},{"text":"Anterior thoracic artery","correct":false,"visible":false},{"text":"Intercostal artery","correct":false,"visible":false}]},{"id":7772,"text":"A 30-year-old female, now 20-weeks pregnant, presents in the emergency room with anorexia, vomiting, and upper abdominal pain for the last 1 month. On examination, she is lethargic, with blood pressure 90/60 mmHg, pulse 120/minute, respiratory rate 30/minute. Her chest is clear while abdomen is mildly tender in epigastrium. Her random blood sugar is 70 mg% and arterial blood gases show a pH of 7.3, pCO2 of 30mmHg, and HCO3 of 16 mEq/L. Urine shows no ketones. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Starvation ketoacidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false}]},{"id":7773,"text":"While explaining the stages of maturation of lungs, the teacher showed a histological slide of the lung in which branching had continued to form terminal bronchioles. There were no respiratory bronchioles or alveoli present. Which of the following stage is it?","explanation":null,"reference":null,"responses":[{"text":"Canalicular","correct":false,"visible":false},{"text":"Alveolar","correct":false,"visible":false},{"text":"Terminal sac","correct":false,"visible":false},{"text":"Post natal","correct":false,"visible":false},{"text":"Pseudoglandular","correct":true,"visible":false}]},{"id":7774,"text":"When foreign objects are aspirated into the trachea, they will usually pass into the right primary bronchus because of which of the following reasons?","explanation":null,"reference":null,"responses":[{"text":"It is at right angle to the left","correct":false,"visible":false},{"text":"It Is more curved, longer and smaller than the left","correct":false,"visible":false},{"text":"It is wider. straighter and shorter than the left","correct":true,"visible":false},{"text":"It lies at a higher level than the left","correct":false,"visible":false},{"text":"It is straighter, longer and larger than the left","correct":false,"visible":false}]},{"id":7775,"text":"pH value can be determined by which of the following?","explanation":null,"reference":null,"responses":[{"text":"pH balancer","correct":false,"visible":false},{"text":"pH detector","correct":false,"visible":false},{"text":"pH spectrometer","correct":false,"visible":false},{"text":"pH electrode","correct":false,"visible":false},{"text":"pH meter","correct":true,"visible":false}]},{"id":7789,"text":"During systole, what is the pressure of the pulmonary artery equal to?","explanation":null,"reference":null,"responses":[{"text":"Right ventricle","correct":true,"visible":false},{"text":"Right atrium","correct":false,"visible":false},{"text":"Left atrium","correct":false,"visible":false},{"text":"Left ventricle","correct":false,"visible":false},{"text":"Superior vena cava","correct":false,"visible":false}]},{"id":7793,"text":"What is the common pathology in chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":null,"responses":[{"text":"Right arterial hypertrophy","correct":false,"visible":false},{"text":"Carotid artery blockage","correct":false,"visible":false},{"text":"Left ventricular hypertrophy","correct":false,"visible":false},{"text":"Right ventricular hypertrophy","correct":true,"visible":false},{"text":"Left arterial hypertrophy","correct":false,"visible":false}]},{"id":7802,"text":"Which of the following is present in the superior mediastinum?","explanation":null,"reference":null,"responses":[{"text":"Arch of aorta","correct":true,"visible":false},{"text":"Bronchus","correct":false,"visible":false},{"text":"Descending aorta","correct":false,"visible":false},{"text":"Phrenic nerve","correct":false,"visible":false},{"text":"Larynx","correct":false,"visible":false}]},{"id":7803,"text":"When is pulmonary resistance increased?","explanation":null,"reference":null,"responses":[{"text":"Vagal inhibition","correct":false,"visible":false},{"text":"Lungs are small","correct":false,"visible":false},{"text":"In sympathetic stimulation","correct":false,"visible":false},{"text":"In parasympathetic inhibition","correct":false,"visible":false},{"text":"During inspiration","correct":true,"visible":false}]},{"id":7804,"text":"The amount of air remaining in the lungs even after forced expiration is known as?","explanation":null,"reference":null,"responses":[{"text":"Expiratory reserve volume","correct":false,"visible":false},{"text":"Inspiratory capacity","correct":false,"visible":false},{"text":"Inspiratory reserve volume","correct":false,"visible":false},{"text":"Residual volume","correct":true,"visible":false},{"text":"Expiratory capacity","correct":false,"visible":false}]},{"id":7806,"text":"The central chemoreceptors are stimulated maximally by which of the following chemical substance?","explanation":"The **central chemoreceptors** are stimulated maximally by a **high concentration of CO₂**.\r\n\r\nCentral chemoreceptors, located near the ventrolateral surface of the medulla oblongata, primarily sense changes in the pH of the cerebrospinal fluid (CSF). While these receptors are not directly sensitive to CO₂, an increase in CO₂ concentration in the blood leads to an increased diffusion of CO₂ into the CSF. Within the CSF, CO₂ reacts with water to form carbonic acid (H₂CO₃), which dissociates into bicarbonate ions and hydrogen ions. This process decreases the pH of the CSF. The resultant increase in hydrogen ion concentration is what stimulates the central chemoreceptors. Consequently, the primary driver for the activation of central chemoreceptors is elevated CO₂ levels, even though the receptors are technically responding to the associated change in pH.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 533.","responses":[{"text":"High concentration of bicarbonate ions","correct":false,"visible":false},{"text":"High pH in blood","correct":false,"visible":false},{"text":"High concentration of CO₂","correct":false,"visible":false},{"text":"Low partial pressure of oxygen","correct":false,"visible":false},{"text":"High concentration of hydrogen ions","correct":true,"visible":false}]},{"id":7807,"text":"Which of the following is a characteristic of the left lung?","explanation":null,"reference":null,"responses":[{"text":"Horizontal fissure","correct":false,"visible":false},{"text":"Lingula of the lung","correct":true,"visible":false},{"text":"A groove for superior vena cava","correct":false,"visible":false},{"text":"Three lobar bronchi","correct":false,"visible":false},{"text":"A larger capacity than right lung","correct":false,"visible":false}]},{"id":7808,"text":"The students of first year MBBS are given a slide of the respiratory system. It shows all the usual layers: mucosa, submucosa, cartilage/muscular layer, and adventitia. Which of the following components of the respiratory airway has the greatest relative amount of smooth muscle?","explanation":"**Bronchi** are indeed characterized by a substantial amount of smooth muscle in their walls.\r\n\r\nThe respiratory system is organized as a branching network, and as we descend from the trachea to the terminal structures of the lungs, there's a variation in the histological makeup of these airways. Among them, the bronchi stand out for their significant smooth muscle component.\r\n\r\nWhile the trachea primarily relies on C-shaped cartilage rings for support, the bronchi, as they branch and reduce in size, exhibit more circular bands of smooth muscle. This arrangement of smooth muscle allows for the constriction and dilation of the bronchi, playing a crucial role in regulating airflow. Although bronchioles also contain smooth muscle, when assessing the relative amount of smooth muscle to the total wall structure, the bronchi have a more pronounced smooth muscle layer compared to other components of the respiratory airway.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 350.","responses":[{"text":"Larynx","correct":false,"visible":false},{"text":"Bronchioles","correct":false,"visible":false},{"text":"Trachea","correct":false,"visible":false},{"text":"Bronchi","correct":true,"visible":false},{"text":"Nasal cavity","correct":false,"visible":false}]},{"id":7810,"text":"A 45-year-old male was diagnosed with a severe right middle lobe infection of the lung. Where on the anterior chest wall, would you auscultate the right middle lobe?","explanation":null,"reference":null,"responses":[{"text":"Sixth intercostal space","correct":false,"visible":false},{"text":"Fourth intercostal space","correct":true,"visible":false},{"text":"Second intercostal space","correct":false,"visible":false},{"text":"Seventh intercostal space","correct":false,"visible":false},{"text":"Superior to middle third of the clavicle","correct":false,"visible":false}]},{"id":7812,"text":"Compensated respiratory acidosis will have which of the following?","explanation":null,"reference":null,"responses":[{"text":"A high CO2, low pH, low bicarbonate","correct":false,"visible":false},{"text":"A low C02, low pH, high bicarbonate","correct":false,"visible":false},{"text":"A low CO2, high pH, high bicarbonate","correct":false,"visible":false},{"text":"A high CO2, low pH, high bicarbonate","correct":true,"visible":false},{"text":"A high CO2, high pH, high bicarbonate","correct":false,"visible":false}]},{"id":7814,"text":"A 46-year-old woman goes to the physician for a routine health maintenance examination. On physical examination, there are no remarkable findings. Her body mass index is 22. She does not smoke. A tuberculin skin test is positive. A chest radiograph shows a solitary, 3-cm left upper lobe mass. The mass is removed during thoracotomy by wedge resection. The microscopic appearance of this lesion shows granulomas. Which of the following is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Lung abscess","correct":false,"visible":false},{"text":"Primary adenocarcinoma","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis infection","correct":true,"visible":false},{"text":"Pulmonary infarction","correct":false,"visible":false},{"text":"Pulmonary hamartoma","correct":false,"visible":false}]},{"id":7815,"text":"Which of the following is the musical sound of the high frequency produced in larger airways due to vibrations in the bronchial wall from airflow velocity and is one of the most common symptoms of chronic asthma?","explanation":null,"reference":null,"responses":[{"text":"Stridor","correct":false,"visible":false},{"text":"Conducted sounds","correct":false,"visible":false},{"text":"Wheezing","correct":true,"visible":false},{"text":"Rales","correct":false,"visible":false},{"text":"Crepitation","correct":false,"visible":false}]},{"id":7816,"text":"In medical sciences, the patient is generally assessed through a biopsychosocial model. In which of the following aspect, there is an emphasis on cultural, environmental, and familial influences on expression and experience of illness?","explanation":null,"reference":null,"responses":[{"text":"Cultural model","correct":false,"visible":false},{"text":"Ecological model","correct":false,"visible":false},{"text":"Social model","correct":true,"visible":false},{"text":"Psychological model","correct":false,"visible":false},{"text":"Biological model","correct":false,"visible":false}]},{"id":7817,"text":"Regarding the structure and functions of the alveoli of the lung, which of the following is mismatched?","explanation":null,"reference":null,"responses":[{"text":"Pneumocyte type Il--\u003estem cell for more pneumocyte types 1 and 2","correct":false,"visible":false},{"text":"Pneumocyte (alveolar cell) type 1--\u003ecytoplasm through which gaseous exchange occurs","correct":false,"visible":false},{"text":"Alveolar macrophage--\u003eremoves inhaled particulates that reach the alveolus","correct":false,"visible":false},{"text":"Pneumocyte type II--\u003esecretes pulmonary surfactant","correct":false,"visible":false},{"text":"Pulmonary surfactant--\u003eincreases surface tension within alveoli","correct":true,"visible":false}]},{"id":7818,"text":"Stimulation of which of the following center leads to active expiration?","explanation":null,"reference":null,"responses":[{"text":"Ventral respiratory group of neurons","correct":true,"visible":false},{"text":"Apneustic center","correct":false,"visible":false},{"text":"Pneumotaxic center","correct":false,"visible":false},{"text":"Central chemoreceptors","correct":false,"visible":false},{"text":"Dorsal respiratory group of neurons","correct":false,"visible":false}]},{"id":7819,"text":"pH can be kept constant with the help of which of the following solutions?","explanation":null,"reference":null,"responses":[{"text":"Super-saturated solution","correct":false,"visible":false},{"text":"Unsaturated solution","correct":false,"visible":false},{"text":"Strong acid solution","correct":false,"visible":false},{"text":"Buffer solution","correct":true,"visible":false},{"text":"Saturated solution","correct":false,"visible":false}]},{"id":7820,"text":"Which of the following pressure differences is responsible for the distention of the lungs?","explanation":null,"reference":null,"responses":[{"text":"Airway closing pressure","correct":false,"visible":false},{"text":"Alveolar pressure","correct":false,"visible":false},{"text":"Transthoracic pressure","correct":false,"visible":false},{"text":"Transpulmonary pressure","correct":true,"visible":false},{"text":"Airway opening pressure","correct":false,"visible":false}]},{"id":7821,"text":"Glomus cells present in the carotid and aortic bodies sense the partial pressure of oxygen in the blood. As the PO2 falls below 60 mmHg, these cells start to depolarize and eventually release neurotransmitters to activate the nerve. What is the basic mechanism by which glomus cells (chemoreceptors) depolarize?","explanation":null,"reference":null,"responses":[{"text":"Closure of potassium channels","correct":true,"visible":false},{"text":"Opening of sodium channels","correct":false,"visible":false},{"text":"Opening of calcium channels","correct":false,"visible":false},{"text":"Closure of sodium channels","correct":false,"visible":false},{"text":"Opening of chloride channels","correct":false,"visible":false}]},{"id":7822,"text":"1 gram of hemoglobin carries which of the following amounts of oxygen?","explanation":null,"reference":null,"responses":[{"text":"1.35 ml","correct":false,"visible":false},{"text":"1 ml","correct":false,"visible":false},{"text":"1.34 ml","correct":true,"visible":false},{"text":"15 ml","correct":false,"visible":false},{"text":"20.1 ml","correct":false,"visible":false}]},{"id":7823,"text":"Which of the following is not found in the interalveolar septum?","explanation":null,"reference":null,"responses":[{"text":"Dust cells","correct":false,"visible":false},{"text":"Blood capillaries","correct":false,"visible":false},{"text":"Reticular fibers","correct":false,"visible":false},{"text":"Elastic fibers","correct":false,"visible":false},{"text":"Neutrophills","correct":true,"visible":false}]},{"id":7824,"text":"Which of the following is not a feature of the right main bronchus?","explanation":null,"reference":null,"responses":[{"text":"It is 6 centimeters in length","correct":true,"visible":false},{"text":"It forms at the level of T4 vertebra","correct":false,"visible":false},{"text":"It lies posterior to the arch of aorta","correct":false,"visible":false},{"text":"Azygos vein arches posteriorly superior to it","correct":false,"visible":false},{"text":"It is more vertical than the left bronchus","correct":false,"visible":false}]},{"id":7825,"text":"Which of the following is helpful in differentiating the trachea from the esophagus?","explanation":null,"reference":null,"responses":[{"text":"Epithelium","correct":true,"visible":false},{"text":"Submucosa","correct":false,"visible":false},{"text":"Adventitia","correct":false,"visible":false},{"text":"Glands","correct":false,"visible":false},{"text":"Blood vessels","correct":false,"visible":false}]},{"id":7826,"text":"Where is the olfactory epithelium found?","explanation":null,"reference":null,"responses":[{"text":"Lateral walls of the nasal cavity","correct":false,"visible":false},{"text":"Pharynx","correct":false,"visible":false},{"text":"Roof of the nasal cavity","correct":true,"visible":false},{"text":"Floor of the nasal cavity","correct":false,"visible":false},{"text":"Medial walls of the nasal cavity","correct":false,"visible":false}]},{"id":7827,"text":"Which of the following does not drain into the thoracic duct?","explanation":null,"reference":null,"responses":[{"text":"Left lower limb","correct":false,"visible":false},{"text":"Left bronchomediastinal trunk","correct":false,"visible":false},{"text":"Right lower limb","correct":false,"visible":false},{"text":"Left intercostal nodes","correct":false,"visible":false},{"text":"Right intercostal nodes","correct":true,"visible":false}]},{"id":7828,"text":"Thromboxane A2 is primarily represented by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Olfactory epithelium","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Platelets","correct":true,"visible":false},{"text":"Respiratory epithelium","correct":false,"visible":false},{"text":"Mast cells","correct":false,"visible":false}]},{"id":7829,"text":"Which of the following represents the mechanism of action of the nonsteroidal anti-inflammatory drugs?","explanation":null,"reference":null,"responses":[{"text":"It inhibits cyclooxygenase pathway","correct":true,"visible":false},{"text":"It inhibits lipoxygenase pathway","correct":false,"visible":false},{"text":"It helps in the formation of prostaglandins","correct":false,"visible":false},{"text":"It helps in metabolizing arachidonic acid","correct":false,"visible":false},{"text":"It helps in the formation of steroids","correct":false,"visible":false}]},{"id":7830,"text":"The trachea bifurcates into two primary bronchi at which of the following levels?","explanation":null,"reference":null,"responses":[{"text":"T1","correct":false,"visible":false},{"text":"T7","correct":false,"visible":false},{"text":"T6","correct":false,"visible":false},{"text":"T5","correct":true,"visible":false},{"text":"T2","correct":false,"visible":false}]},{"id":7831,"text":"How much carbon dioxide is transferred per 100 ml of blood from the tissues to the lungs?","explanation":null,"reference":null,"responses":[{"text":"20 ml","correct":false,"visible":false},{"text":"7 ml","correct":false,"visible":false},{"text":"52 ml","correct":false,"visible":false},{"text":"48 ml","correct":false,"visible":false},{"text":"4 ml","correct":true,"visible":false}]},{"id":7832,"text":"Pleural effusion is checked on X-ray at which of the following levels?","explanation":"Pleural effusion, an accumulation of excess fluid in the pleural cavity, is best identified on an X-ray at the **costophrenic angle**. This angle is where the diaphragm (the primary muscle of respiration) meets the rib cage, specifically at the lateral-most aspect of the ribcage on a frontal chest X-ray.\r\n\r\nOn a normal X-ray, the costophrenic angles appear sharp. However, in the presence of a pleural effusion, these angles become blunted or obscured due to the fluid accumulation. This blunting is often one of the earliest radiographic signs of a pleural effusion. Lateral chest X-rays can also provide additional views of the costophrenic angle and further aid in diagnosis.","reference":"Chest x-ray abnormalities. Accessed May 20, 2023. https://www.radiologymasterclass.co.uk/tutorials/chest/chest_pathology/chest_pathology_page6","responses":[{"text":"Cardiophrenic angle","correct":false,"visible":false},{"text":"Base of the lungs","correct":false,"visible":false},{"text":"Sternal angle","correct":false,"visible":false},{"text":"Infrasternal angle","correct":false,"visible":false},{"text":"Costophrenic angle","correct":true,"visible":false}]},{"id":7833,"text":"Which of the following molecular substances plays an important role in the adhesion-rolling phase of the leukocytes recruitment?","explanation":null,"reference":null,"responses":[{"text":"Leukotrienes","correct":false,"visible":false},{"text":"Histaminase","correct":false,"visible":false},{"text":"C3b receptor","correct":false,"visible":false},{"text":"L, P and E selectins","correct":true,"visible":false},{"text":"Tumor necrosis factor","correct":false,"visible":false}]},{"id":7834,"text":"What percentage of carbondioxide is carried in the form of bicarbonates in the plasma?","explanation":null,"reference":null,"responses":[{"text":"97%","correct":false,"visible":false},{"text":"70%","correct":true,"visible":false},{"text":"10%","correct":false,"visible":false},{"text":"30%","correct":false,"visible":false},{"text":"50%","correct":false,"visible":false}]},{"id":7835,"text":"A patient presented to the emergency department with a respiratory rate of 8 breaths/min and was drowsy. His attendant told the doctor that he reported a stiff chest and had been unable to breathe properly. During further investigation, the doctor came to know that the patient had been suffering from emphysema. Which of the following conditions is most likely be the case?","explanation":null,"reference":null,"responses":[{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Metabolic acidosis followed by respiratory compensation","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":true,"visible":false}]},{"id":7836,"text":"Celiac and stellate ganglions are the sympathetic ganglions. Which of the following ganglions is also included in this category?","explanation":null,"reference":null,"responses":[{"text":"Otic ganglion","correct":false,"visible":false},{"text":"Dorsal vagus nucleus","correct":false,"visible":false},{"text":"Ciliary ganglion","correct":false,"visible":false},{"text":"Dorsal root ganglion","correct":false,"visible":false},{"text":"Ganglion impar","correct":true,"visible":false}]},{"id":7837,"text":"The diffusion of gases increases even at normal partial pressure due to which reason?","explanation":null,"reference":null,"responses":[{"text":"Decreased velocity","correct":false,"visible":false},{"text":"Increased surface area","correct":true,"visible":false},{"text":"Decreased solubility","correct":false,"visible":false},{"text":"Decreased surface area","correct":false,"visible":false},{"text":"Solubility of gas","correct":false,"visible":false}]},{"id":7838,"text":"Which of the following is not a bronchodilator?","explanation":null,"reference":null,"responses":[{"text":"Epinephrine","correct":false,"visible":false},{"text":"Anti-histamine","correct":false,"visible":false},{"text":"Anti-adrenergic drugs","correct":false,"visible":false},{"text":"Acetylcholine","correct":true,"visible":false},{"text":"Levalbuterol","correct":false,"visible":false}]},{"id":7839,"text":"Which of the following statements is wrong regarding the internal thoracic artery?","explanation":null,"reference":null,"responses":[{"text":"It arises from the third part of the subclavian artery","correct":true,"visible":false},{"text":"It runs posterior to upper six costal cartilages","correct":false,"visible":false},{"text":"Musculophrenic artery arises from the internal thoracic artery as its terminal branch","correct":false,"visible":false},{"text":"It gives rise to anterior intercostal arteries","correct":false,"visible":false},{"text":"It runs superficial to the vagus nerve","correct":false,"visible":false}]},{"id":7840,"text":"Which of the following is correct about the role of Clara cells in reducing surface tension and prevention of collapse of airways?","explanation":null,"reference":null,"responses":[{"text":"By secreting surfactant","correct":true,"visible":false},{"text":"By engulfing microorganisms","correct":false,"visible":false},{"text":"By producing mucus","correct":false,"visible":false},{"text":"By replacing the damaged cells","correct":false,"visible":false},{"text":"By their ciliary activity","correct":false,"visible":false}]},{"id":7842,"text":"In which of the following weeks does the respiratory diverticulum (lung bud) appear as an outgrowth from the ventral wall of the foregut?","explanation":null,"reference":null,"responses":[{"text":"7th","correct":false,"visible":false},{"text":"6th","correct":false,"visible":false},{"text":"8th","correct":false,"visible":false},{"text":"4th","correct":true,"visible":false},{"text":"5th","correct":false,"visible":false}]},{"id":7843,"text":"A child developed a common cold during his trip to northern areas and his parents are worried because the child has been a patient of asthma, but after taking complete medications it was cured. They read it somewhere that there are some structural changes that occur in the airway of asthmatic patients. What are the structural changes that develop in patients with asthma and how do they increase the risk of asthma recurrence?","explanation":null,"reference":null,"responses":[{"text":"Increased inflammation in bacterial infections","correct":false,"visible":false},{"text":"Smooth muscle hypertrophy which increase chances of reversible bronchoconstriction","correct":true,"visible":false},{"text":"Alveolar walls degenerate causing less gaseous exchange","correct":false,"visible":false},{"text":"Increased sensitivity followed by fainting and blue lips","correct":false,"visible":false},{"text":"Alveolar capillaries are constricted that collapse of bronchioles","correct":false,"visible":false}]},{"id":7844,"text":"Asthma is characterized by reversible bronchoconstriction caused by airway hyperresponsiveness to a variety of stimuli. Which of the following are risk factors for the development of asthma?","explanation":null,"reference":null,"responses":[{"text":"High birth weight","correct":false,"visible":false},{"text":"Exposure to alcohol","correct":false,"visible":false},{"text":"High body-mass-index","correct":false,"visible":false},{"text":"Exposure to radiation","correct":false,"visible":false},{"text":"Exposure to air-borne allergens","correct":true,"visible":false}]},{"id":7845,"text":"Chronic bronchitis is characterized by the destruction of smooth muscle and elastic tissue leading to permanent dilatation of airways. Which of the following are the major morphological changes seen in chronic bronchitis?","explanation":null,"reference":null,"responses":[{"text":"Slight increase in goblet cell number but markedly so in small airways","correct":false,"visible":false},{"text":"Increased mucosal gland depth compared to the thickness of the wall between the epithelium and the cartilage","correct":true,"visible":false},{"text":"Smooth muscle hypertrophy","correct":false,"visible":false},{"text":"Predominant lymphocyte infiltration","correct":false,"visible":false},{"text":"Reid index of 0.4 is normal and is observed in chronic bronchitis","correct":false,"visible":false}]},{"id":7846,"text":"Asthma is characterized by chest tightness, wheezing, sputum production, cough, and airway hyperresponsiveness. Which one of the following is the most characteristic factor of bronchial asthma?","explanation":null,"reference":null,"responses":[{"text":"Reversible lower airway constriction","correct":true,"visible":false},{"text":"Symptoms are the same for every person with asthma","correct":false,"visible":false},{"text":"Persistent symptoms","correct":false,"visible":false},{"text":"Irreversible lower airway constriction","correct":false,"visible":false},{"text":"Destruction of smooth muscle","correct":false,"visible":false}]},{"id":7847,"text":"Which of the following statements is incorrect regarding the embryonic development of vertebrae?","explanation":null,"reference":null,"responses":[{"text":"Vertebrae develop from sclerotome portions of somites","correct":false,"visible":false},{"text":"Caudal and cranial ends of adjacent sclerotomes fuse","correct":false,"visible":false},{"text":"Notochord remnants are in the form of nucleus pulposus","correct":false,"visible":false},{"text":"Sclerotomes migrate around notochord in the 6th week","correct":true,"visible":false},{"text":"Mesenchymal cells between sclerotomes form intervertebral discs","correct":false,"visible":false}]},{"id":7848,"text":"In the right lung, oblique fissure separates which of the following?","explanation":null,"reference":null,"responses":[{"text":"Superior lobe from posterior lobe","correct":false,"visible":false},{"text":"Middle lobe from inferior lobe","correct":true,"visible":false},{"text":"Anterior lobe from posterior lobe","correct":false,"visible":false},{"text":"Superior lobe from middle lobe","correct":false,"visible":false},{"text":"Superior lobe from inferior lobe","correct":false,"visible":false}]},{"id":7849,"text":"Which of the following is the most common age for the development of atopic asthma?","explanation":null,"reference":null,"responses":[{"text":"Childhood","correct":true,"visible":false},{"text":"Teenage","correct":false,"visible":false},{"text":"Old age","correct":false,"visible":false},{"text":"Adulthood","correct":false,"visible":false},{"text":"Neonatal","correct":false,"visible":false}]},{"id":7851,"text":"The esophagus lies medial to the aorta in which of the following regions?","explanation":null,"reference":null,"responses":[{"text":"Middle mediastinum","correct":false,"visible":false},{"text":"The lower part of thoracic cavity just before it enters the abdomen","correct":false,"visible":false},{"text":"Anterior mediastinum","correct":false,"visible":false},{"text":"Superior mediastinum","correct":true,"visible":false},{"text":"Root of the neck","correct":false,"visible":false}]},{"id":7852,"text":"What does empathy mean in a doctor-patient relationship?","explanation":null,"reference":null,"responses":[{"text":"Doctor should feel what the patient feels","correct":false,"visible":false},{"text":"Doctor should be careful","correct":false,"visible":false},{"text":"Doctor should be ignorant towards the patient's feelings","correct":false,"visible":false},{"text":"Doctor should understand what the patient is feeling","correct":true,"visible":false},{"text":"Doctor should not listen to the patient","correct":false,"visible":false}]},{"id":7853,"text":"When the PO2 falls below 73 mmHg in alveolar air, which of the following occurs in the lungs?","explanation":null,"reference":null,"responses":[{"text":"Expansion of alveoli","correct":false,"visible":false},{"text":"Decreased physiological shunt","correct":false,"visible":false},{"text":"Damage to type-1 pneumocytes","correct":false,"visible":false},{"text":"Constriction of blood vessels adjacent to alveoli","correct":true,"visible":false},{"text":"Nitrogen content increases","correct":false,"visible":false}]},{"id":7854,"text":"Which of the following is the structure that leaves the most pronounced impression on the right lung of the cadaver?","explanation":null,"reference":null,"responses":[{"text":"Right vagus nerve","correct":false,"visible":false},{"text":"Right common carotid artery","correct":false,"visible":false},{"text":"Azygous vein","correct":true,"visible":false},{"text":"Thoracic aorta","correct":false,"visible":false},{"text":"Right phrenic nerve","correct":false,"visible":false}]},{"id":7855,"text":"Which of the following is related to persistent asthma?","explanation":null,"reference":null,"responses":[{"text":"Irreversible bronchoconstriction of lower airways","correct":false,"visible":false},{"text":"Reversible bronchoconstriction of upper airways","correct":false,"visible":false},{"text":"Reversible bronchoconstriction of lower airways","correct":true,"visible":false},{"text":"Irreversible bronchoconstriction of upper airways","correct":false,"visible":false},{"text":"Permanent dilation of airways","correct":false,"visible":false}]},{"id":7856,"text":"Which of the following best describes the flail chest?","explanation":null,"reference":null,"responses":[{"text":"First rib is fractured","correct":false,"visible":false},{"text":"More than 3 ribs are fractured at 2 places","correct":true,"visible":false},{"text":"Multiple ribs are fractured","correct":false,"visible":false},{"text":"Rib is fractured at the costal cartilage","correct":false,"visible":false},{"text":"More than 3 ribs are fractured at one place","correct":false,"visible":false}]},{"id":7857,"text":"What is the reason behind respiration being abdominal in infants?","explanation":null,"reference":null,"responses":[{"text":"Obliquity of ribs","correct":false,"visible":false},{"text":"Increased elasticity of chest wall","correct":false,"visible":false},{"text":"Presence of accessory cervical ribs","correct":false,"visible":false},{"text":"Horizontal predisposition of ribs","correct":true,"visible":false},{"text":"Bucket handle movement of ribs","correct":false,"visible":false}]},{"id":7859,"text":"Which of the following structure contains the greatest number of elastic fibers?","explanation":null,"reference":null,"responses":[{"text":"Alveolar duct","correct":false,"visible":false},{"text":"Respiratory bronchioles","correct":false,"visible":false},{"text":"Interalveolar septum","correct":false,"visible":false},{"text":"Alveolar capillaries","correct":false,"visible":false},{"text":"Alveolar sac","correct":true,"visible":false}]},{"id":7861,"text":"Which of the following factors shifts the oxygen dissociation curve to the right?","explanation":null,"reference":null,"responses":[{"text":"Low temperature","correct":false,"visible":false},{"text":"High pH","correct":false,"visible":false},{"text":"Strenuous exercise","correct":true,"visible":false},{"text":"Low concentration of 2,3 DPG","correct":false,"visible":false},{"text":"Fetal hemoglobin","correct":false,"visible":false}]},{"id":7867,"text":"Which of the following is the correct X-ray orientation for chest lesions?","explanation":null,"reference":null,"responses":[{"text":"Lateral view","correct":false,"visible":false},{"text":"Supine view","correct":false,"visible":false},{"text":"Posteroanterior view","correct":true,"visible":false},{"text":"Anteroposterior errect view","correct":false,"visible":false},{"text":"Anteroposterior view","correct":false,"visible":false}]},{"id":7873,"text":"Which one of the following represents the tidal volume?","explanation":null,"reference":null,"responses":[{"text":"The volume that remains in the lungs after forced expiration","correct":false,"visible":false},{"text":"The volume of air inhaled or exhaled during normal breathing","correct":true,"visible":false},{"text":"The volume exhaled in forced expiration","correct":false,"visible":false},{"text":"The maximum amount of air that can be inhaled","correct":false,"visible":false},{"text":"The volume that remains in the lungs after normal expiration","correct":false,"visible":false}]},{"id":7889,"text":"Which one of the following represents pressure change in the thoracic cage during inspiration?","explanation":null,"reference":null,"responses":[{"text":"More positive than +4  mm of Hg","correct":false,"visible":false},{"text":"More negative than 0.4  mm of Hg","correct":false,"visible":false},{"text":"More negative than -4 mm of Hg","correct":true,"visible":false},{"text":"More negative pressure than +2  mm of Hg","correct":false,"visible":false},{"text":"More negative than -2  mm of Hg","correct":false,"visible":false}]},{"id":7896,"text":"Which of the following represents compliance of both the lungs?","explanation":null,"reference":null,"responses":[{"text":"600 ml/cm of H2O","correct":false,"visible":false},{"text":"110 ml/cm of H2O","correct":false,"visible":false},{"text":"50 ml/cm of H2O","correct":false,"visible":false},{"text":"200 ml/cm of H2O","correct":true,"visible":false},{"text":"400 ml/cm of H2O","correct":false,"visible":false}]},{"id":7899,"text":"Which of the following events only occurs in the forced inspiration?","explanation":null,"reference":null,"responses":[{"text":"Relaxation of internal intercostals","correct":false,"visible":false},{"text":"Elevation of 2-7 ribs","correct":false,"visible":false},{"text":"Elevation of first rib","correct":true,"visible":false},{"text":"Contraction of diaphragm","correct":false,"visible":false},{"text":"Contraction of external intercostal muscles","correct":false,"visible":false}]},{"id":7903,"text":"Which of the following represents arterial partial pressure of oxygen?","explanation":null,"reference":null,"responses":[{"text":"55 mm of Hg","correct":false,"visible":false},{"text":"20 mm of Hg","correct":false,"visible":false},{"text":"70 mm of Hg","correct":false,"visible":false},{"text":"75 mm of Hg","correct":false,"visible":false},{"text":"95 mm of Hg","correct":true,"visible":false}]},{"id":7948,"text":"Which of the following is a characteristic feature of the twelfth rib?","explanation":"The twelfth rib, also known as the last or the most inferior of the true ribs, has several unique anatomical characteristics that distinguish it from other ribs. Out of the provided options:\r\n\r\n- **Costal cartilage:** Every rib has costal cartilage, though the twelfth rib's cartilage is short and does not articulate anteriorly with the sternum.\r\n  \r\n- **Neck of the rib:** The twelfth rib typically lacks a neck.\r\n\r\n- **Angle of the rib:** The angle is not a distinguishing feature of the twelfth rib, as all ribs have angles.\r\n\r\n- **Single facet on head:** This is a **characteristic feature** of the twelfth rib. Unlike most other ribs that articulate with two adjacent vertebrae and have two facets (demifacets) on their heads, the twelfth rib only articulates with its corresponding vertebra (T12) and has a **single facet**.\r\n\r\n- **Costal groove:** Found on most ribs and is not unique to the twelfth rib.","reference":"Moore, Keith L., A. M. R. Agur, and Arthur F. Dalley. Clinically Oriented Anatomy. 8th ed. Philadelphia: Wolters Kluwer, 2018: 76.","responses":[{"text":"Single facet on head","correct":true,"visible":false},{"text":"Costal cartilage","correct":false,"visible":false},{"text":"Neck of the rib","correct":false,"visible":false},{"text":"Costal groove","correct":false,"visible":false},{"text":"Angle of the rib","correct":false,"visible":false}]},{"id":7949,"text":"Which of the following types of mediastinum consists of esophagus, thoracic duct, and sympathetic chain?","explanation":null,"reference":null,"responses":[{"text":"Inferior mediastinum","correct":false,"visible":false},{"text":"Anterior mediastinum","correct":false,"visible":false},{"text":"Posterior mediastinum","correct":true,"visible":false},{"text":"Middle mediastinum","correct":false,"visible":false},{"text":"Superior mediastinum","correct":false,"visible":false}]},{"id":7951,"text":"In a chest X-ray, a doctor sees a rib that articulates with both the manubrium and the body of the sternum. Which of the following is an atypical feature of this rib?","explanation":null,"reference":null,"responses":[{"text":"Tuberosity","correct":false,"visible":false},{"text":"Neck","correct":false,"visible":false},{"text":"Tubercle for serratus anterior","correct":true,"visible":false},{"text":"Costal groove","correct":false,"visible":false},{"text":"Single facet on head","correct":false,"visible":false}]},{"id":7953,"text":"A patient had tuberculosis and was advised anti-tuberculosis therapy but stopped after 7 days on the advice of the physician. He had developed pleuritis as tuberculosis has extended into the cavity. What other conditions can cause pleuritis?","explanation":null,"reference":null,"responses":[{"text":"All of these","correct":true,"visible":false},{"text":"Mediastinal lymphadenitis","correct":false,"visible":false},{"text":"Lung carcinoma","correct":false,"visible":false},{"text":"Loffler's pneumonia","correct":false,"visible":false},{"text":"Pericarditis","correct":false,"visible":false}]},{"id":7954,"text":"Which of the following is an inappropriate statement regarding respiratory bronchioles?","explanation":null,"reference":null,"responses":[{"text":"Lack glands in its walls","correct":false,"visible":false},{"text":"Lack goblet cells","correct":false,"visible":false},{"text":"First part of the respiratory portion","correct":false,"visible":false},{"text":"Have an interruption of alveoli in its walls","correct":false,"visible":false},{"text":"Lack clara cells","correct":true,"visible":false}]},{"id":7959,"text":"Which of the following is not a distinguishing feature between bronchus and bronchiole?","explanation":null,"reference":null,"responses":[{"text":"Diameter of lumen","correct":false,"visible":false},{"text":"Presence of smooth muscles","correct":true,"visible":false},{"text":"Presence of glands","correct":false,"visible":false},{"text":"Type of cartilage","correct":false,"visible":false},{"text":"Type of epithelium","correct":false,"visible":false}]}
]

